#nullable enable // autogenerated

using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Stages;
using MVZ2Logic.Definitions;
using MVZ2Logic.IZombie;
using Tools;

namespace MVZ2.GameContent.IZombie
{
    [AutoIZombieLayoutDefinition(VanillaIZombieLayoutNames.izeComposite2)]
    public class IZEComposite2Layout : IZELayout
    {
        public IZEComposite2Layout(string nsp, string name) : base(nsp, name)
        {
        }
        protected override void FillEndlessContraptions(IIZombieMap map, RandomGenerator rng)
        {
            RandomFill(map, VanillaContraptionID.pistenser, 1, rng);
            RandomFill(map, VanillaContraptionID.punchton, 1, rng);
            RandomFill(map, VanillaContraptionID.silvenser, 1, rng);
            RandomFill(map, VanillaContraptionID.magichest, 1, rng);
            RandomFill(map, VanillaContraptionID.gravityPad, 1, rng); // Does not count
            RandomFill(map, VanillaContraptionID.totenser, 1, rng);
            RandomFill(map, VanillaContraptionID.woodenDropper, 1, rng);
            RandomFill(map, VanillaContraptionID.spikeBlock, 1, rng);
            RandomFill(map, VanillaContraptionID.hellfire, 1, rng);

            // Chapter 5
            RandomFill(map, VanillaContraptionID.triplenser, 1, rng);
            RandomFill(map, VanillaContraptionID.fireworkDispenser, 1, rng);
            RandomFill(map, VanillaContraptionID.repeatenser, 1, rng);
            RandomFill(map, VanillaContraptionID.beacon, 1, rng);
            RandomFill(map, VanillaContraptionID.elasticCloud, 1, rng);

            // Chapter 6
            RandomFill(map, VanillaContraptionID.transfenser, 1, rng);
            RandomFill(map, VanillaContraptionID.gravelpult, 1, rng);
            RandomFill(map, VanillaContraptionID.cursedCandle, 1, rng);
            RandomFill(map, VanillaContraptionID.stoneEye, 1, rng);
        }
    }
}
